const msg = $input.first().json?.message;
if (!msg) return [];

const isVoice = !!msg.voice;
const isText  = !!msg.text;
if (!isVoice && !isText) return [];

return [{ json: {
  chatId:   msg.chat.id,
  userId:   msg.from?.id,
  username: msg.from?.first_name || 'Пользователь',
  isVoice,
  text:     msg.text || '',
  fileId:   isVoice ? msg.voice.file_id : null
}}];

const whisper = $input.first().json;
const src = $('Parse Message').item.json;
return [{ json: {
  userText: whisper.text,
  chatId:   src.chatId,
  userId:   src.userId,
  username: src.username,
  isVoice:  true
}}];

const d = $input.first().json;
return [{ json: {
  userText: d.text,
  chatId:   d.chatId,
  userId:   d.userId,
  username: d.username,
  isVoice:  false
}}];

// ===== MEMORY + AGENTS + LLM REQUEST =====
const d = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const userId = d.userId || d.chatId;

// Load conversation history
const history = staticData.history || {};
const userHistory = history[userId] || [];

// Route: determine agent based on user intent
const text = d.userText.toLowerCase();
let agent = 'general';

if (text.match(/.*(найди|поиск|гугл|search|найд|интернет|узнай).*/)) {
  agent = 'search';
} else if (text.match(/.*(напомн|будильник|таймер|через ).*/)) {
  agent = 'reminder';
} else if (text.match(/.*(задач|task|todo list|список дел|покажи задач).*/)) {
  agent = 'tasks';
} else if (text.match(/.*(календар|calendar|встреч|событие|расписан).*/)) {
  agent = 'calendar';
}

// Agent: Tasks (CRUD)
if (agent === 'tasks') {
  const tasks = staticData.tasks || {};
  if (!tasks[userId]) tasks[userId] = [];

  const lower = d.userText.toLowerCase();
  let reply = '';

  if (lower.match(/^добавь |^добавить |^новая задача |^todo /i)) {
    const taskText = d.userText.replace(/^(добавь |добавить |новая задача |todo )/i, '').trim();
    tasks[userId].push({ id: Date.now(), text: taskText, done: false });
    reply = 'Добавлена: ' + taskText + '\nВсего задач: ' + tasks[userId].length;
  } else if (lower.match(/^выполни |^сделал |^удали |^выполнил /i)) {
    const num = parseInt(text.match(/\d+/)?.[0]);
    if (num && tasks[userId][num - 1]) {
      const t = tasks[userId][num - 1];
      if (lower.startsWith('удали')) {
        tasks[userId].splice(num - 1, 1);
        reply = 'Удалена: ' + t.text;
      } else {
        t.done = true;
        reply = 'Выполнено: ' + t.text;
      }
    } else {
      reply = 'Не нашёл задачу с таким номером.';
    }
  } else if (lower.match(/^список |^задач|^todo list|^покаж/i)) {
    const list = tasks[userId].map((t, i) => (t.done ? '✅' : '⬜') + ' ' + (i+1) + '. ' + t.text).join('\n');
    reply = list || 'Список задач пуст. Скажи "добавь задачу ..."';
  }

  if (reply) {
    staticData.tasks = tasks;
    return [{ json: { ...d, userId, agent, text: reply, bypassLLM: true }}];
  }
}

// Agent: Reminder
if (agent === 'reminder') {
  const reminders = staticData.reminders || {};
  if (!reminders[userId]) reminders[userId] = [];

  const relMatch = text.match(/через\s+(\d+)\s+(минут|часов|секунд|минуту|час)/i);
  if (relMatch) {
    const amount = parseInt(relMatch[1]);
    const unit = relMatch[2].toLowerCase();
    let ms = amount * 60000;
    if (unit.startsWith('час')) ms = amount * 3600000;
    else if (unit.startsWith('сек')) ms = amount * 1000;

    const reminderText = d.userText.replace(/.*?(напомни|напомни мне).*/i, '').trim() || 'Напоминание';
    const fireTime = new Date(Date.now() + ms).toISOString();
    reminders[userId].push({ id: Date.now(), text: reminderText, fireAt: fireTime });
    staticData.reminders = reminders;

    const unitStr = unit.startsWith('час') ? 'час(ов)' : (unit.startsWith('сек') ? 'секунд' : 'минут');
    const reply = 'Напомню через ' + amount + ' ' + unitStr + ': ' + reminderText;
    return [{ json: { ...d, userId, agent, text: reply, bypassLLM: true }}];
  }

  const timeMatch = text.match(/в\s+(\d{1,2})[:\.](\d{2})/);
  if (timeMatch) {
    const h = parseInt(timeMatch[1]);
    const m = parseInt(timeMatch[2]);
    const now = new Date();
    const fire = new Date(now.getFullYear(), now.getMonth(), now.getDate(), h, m);
    if (fire <= now) fire.setDate(fire.getDate() + 1);

    const reminderText = d.userText.replace(/.*?(напомни|напомни мне).*/i, '').trim() || 'Напоминание';
    reminders[userId].push({ id: Date.now(), text: reminderText, fireAt: fire.toISOString() });
    staticData.reminders = reminders;

    const reply = 'Напомню в ' + String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ': ' + reminderText;
    return [{ json: { ...d, userId, agent, text: reply, bypassLLM: true }}];
  }
}

// Agent: Search
if (agent === 'search') {
  const https = require('https');
  const searchQuery = d.userText.replace(/.*(найди|поиск|гугл|search|найд|узнай).*/i, '').trim() || d.userText;

  try {
    const html = await new Promise((resolve, reject) => {
      const url = 'https://html.duckduckgo.com/html/?q=' + encodeURIComponent(searchQuery);
      https.get(url, { headers: { 'User-Agent': 'Mozilla/5.0' }}, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => resolve(data));
      }).on('error', reject);
    });

    const results = [];
    const regex = /<a[^>]+class="result__a"[^>]*href="([^"]+)"[^>]*>([^<]+)<\/a>[\s\S]*?<a[^>]+class="result__snippet"[^>]*>([\s\S]*?)<\/a>/gi;
    let match;
    let count = 0;
    while ((match = regex.exec(html)) !== null && count < 3) {
      const snippet = match[3].replace(/<[^>]+>/g, '').trim();
      if (snippet) {
        results.push(match[2] + ': ' + snippet);
        count++;
      }
    }

    const searchResult = results.length > 0 ? results.join('\n\n') : 'Ничего не найдено.';
    return [{ json: { ...d, userId, agent, searchResult, searchQuery, bypassLLM: false }}];
  } catch (e) {
    return [{ json: { ...d, userId, agent: 'general', searchResult: null, bypassLLM: false }}];
  }
}

// Default: go to LLM
return [{ json: { ...d, userId, agent, bypassLLM: false }}];

// Build LLM request with conversation history
const d = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const userId = d.userId;
const userHistory = (staticData.history || {})[userId] || [];

// Build system prompt based on agent
const systemPrompts = {
  search: 'Ты ассистент с результатами поиска. Суммируй найденное кратко, по-русски. Ссылайся на источники.\n\n' + (d.searchResult || ''),
  tasks: 'Ты ассистент по задачам. Помогай управлять списком дел. Отвечай кратко, по-русски.',
  reminder: 'Ты ассистент по напоминаниям. Помоги пользователю установить напоминание. Отвечай кратко, по-русски.',
  calendar: 'Ты ассистент по календарю. Помогай с расписанием и встречами. Отвечай кратко, по-русски.',
  general: 'Ты умный персональный ассистент по имени Мичи. Отвечай кратко, по-русски, дружелюбно. Помогаешь с вопросами, задачами и напоминаниями.'
};

const agent = d.agent || 'general';
const systemPrompt = systemPrompts[agent] || systemPrompts.general;

let messages;
if (userHistory.length > 0) {
  messages = [
    { role: 'system', content: systemPrompt },
    ...userHistory.slice(-10),
    { role: 'user', content: d.userText }
  ];
} else {
  messages = [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: d.userText }
  ];
}

const body = JSON.stringify({
  model: 'gpt-4o-mini',
  messages,
  temperature: 0.7,
  max_tokens: 500
});

return [{ json: { ...d, apiBody: body }}];

const resp = $input.first().json;
const text = resp.choices?.[0]?.message?.content || 'Не удалось получить ответ';
const d = $input.first().json;
return [{ json: { chatId: d.chatId, isVoice: d.isVoice, userId: d.userId, text, agent: d.agent }}];

// Merge: comes from LLM path or direct from agent
const input = $input.all();
return input;

// Save conversation to static data
const all = $input.all();
const staticData = $getWorkflowStaticData('global');
const history = staticData.history || {};

for (const item of all) {
  const d = item.json;
  if (!d.userId || !d.text) continue;
  const userId = d.userId;
  if (!history[userId]) history[userId] = [];

  // Get original user input
  const parseNode = $('Parse Message');
  const voiceNode = $('Set Voice Input');
  let userInput = '';
  for (let i = 0; i < parseNode.runs.length; i++) {
    if (parseNode.item(i)?.json?.userId == userId || parseNode.item(i)?.json?.chatId == d.chatId) {
      userInput = parseNode.item(i).json.text || userInput;
      break;
    }
  }
  if (!userInput && voiceNode.runs.length > 0) {
    for (let i = 0; i < voiceNode.runs.length; i++) {
      if (voiceNode.item(i)?.json?.userText) {
        userInput = voiceNode.item(i).json.userText;
        break;
      }
    }
  }

  if (userInput) {
    history[userId].push({ role: 'user', content: userInput });
  }
  history[userId].push({ role: 'assistant', content: d.text });

  // Keep last 20 messages
  if (history[userId].length > 20) {
    history[userId] = history[userId].slice(-20);
  }
}

staticData.history = history;
return all;

const chatId = $('Save History').item.json.chatId;
const binaryData = $input.first().binary?.data;
if (!binaryData) throw new Error('No audio binary data');

const audioBuffer = Buffer.from(binaryData.data, 'base64');
const boundary = '----n8nboundary' + Date.now();

let body = Buffer.concat([
  Buffer.from('--' + boundary + '\r\nContent-Disposition: form-data; name="chat_id"\r\n\r\n' + chatId + '\r\n'),
  Buffer.from('--' + boundary + '\r\nContent-Disposition: form-data; name="audio"; filename="voice.mp3"\r\nContent-Type: audio/mpeg\r\n\r\n'),
  audioBuffer,
  Buffer.from('\r\n--' + boundary + '--\r\n')
]);

const token = $env.TELEGRAM_BOT_TOKEN;
const https = require('https');

await new Promise((resolve, reject) => {
  const options = {
    hostname: 'api.telegram.org',
    path: '/bot' + token + '/sendAudio',
    method: 'POST',
    headers: {
      'Content-Type': 'multipart/form-data; boundary=' + boundary,
      'Content-Length': body.length
    }
  };
  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => resolve(JSON.parse(data)));
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});

return [{ json: { ok: true } }];
